class Solution {
    /**
     * Returns the total number of times the given digit appears in the decimal representation of all numbers in nums.
     *
     * @param nums The array of integers.
     * @param digit The digit to count.
     * @return The total count.
     */
    public static long solve(long[] nums, long digit) {
        int d = (int) digit;
        long count = 0;

        for (long num : nums) {
            String s = String.valueOf(num);
            char targetChar = Character.forDigit(d, 10);
            for (int i = 0; i < s.length(); i++) {
                if (s.charAt(i) == targetChar) {
                    count++;
                }
            }
        }
        return count;
    }
}
